class MainActivity : AppCompatActivity() {
    private lateinit var webView: WebView
    private var filePathCallback: ValueCallback<Array<Uri>>? = null
    private var cameraImageUri: Uri? = null
    
    private val cameraPermissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        if (isGranted) {
            openCamera()
        } else {
            Toast.makeText(this, "Camera permission denied", Toast.LENGTH_SHORT).show()
        }
    }
    
    private val fileChooserLauncher = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) { result ->
        if (result.resultCode == Activity.RESULT_OK) {
            val data = result.data
            val results = if (data?.data != null) {
                arrayOf(data.data!!)
            } else if (cameraImageUri != null) {
                arrayOf(cameraImageUri!!)
            } else {
                null
            }
            filePathCallback?.onReceiveValue(results)
            filePathCallback = null
            cameraImageUri = null
        } else {
            filePathCallback?.onReceiveValue(null)
            filePathCallback = null
            cameraImageUri = null
        }
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        webView = WebView(this)
        setContentView(webView)
        
        setupWebView()
        
        webView.loadUrl("https://your-web-app.com")
    }

    private fun setupWebView() {
        webView.settings.apply {
            javaScriptEnabled = true
            domStorageEnabled = true
            databaseEnabled = true
            cacheMode = WebSettings.LOAD_DEFAULT
            allowFileAccess = true
            allowContentAccess = true
            javaScriptCanOpenWindowsAutomatically = true
            setSupportMultipleWindows(false)
            mediaPlaybackRequiresUserGesture = false
        }

        webView.addJavascriptInterface(WebAppInterface(this), "NativeBridge")

        webView.webViewClient = object : WebViewClient() {
            override fun shouldOverrideUrlLoading(
                view: WebView?,
                request: WebResourceRequest?
            ): Boolean {
                return false
            }

            override fun onPageFinished(view: WebView?, url: String?) {
                super.onPageFinished(view, url)
            }
        }

        webView.webChromeClient = object : WebChromeClient() {
            override fun onShowFileChooser(
                webView: WebView?,
                filePathCallback: ValueCallback<Array<Uri>>?,
                fileChooserParams: FileChooserParams?
            ): Boolean {
                this@MainActivity.filePathCallback?.onReceiveValue(null)
                this@MainActivity.filePathCallback = filePathCallback

                val acceptTypes = fileChooserParams?.acceptTypes
                val captureEnabled = fileChooserParams?.isCaptureEnabled ?: false

                if (captureEnabled && acceptTypes != null && acceptTypes.contains("image/*")) {
                    checkCameraPermission()
                } else {
                    openFileChooser()
                }
                return true
            }

            override fun onPermissionRequest(request: PermissionRequest?) {
                request?.grant(request.resources)
            }
        }
    }

    private fun checkCameraPermission() {
        when {
            ContextCompat.checkSelfPermission(
                this,
                Manifest.permission.CAMERA
            ) == PackageManager.PERMISSION_GRANTED -> {
                openCamera()
            }
            else -> {
                cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
            }
        }
    }

    private fun openCamera() {
        val values = ContentValues().apply {
            put(MediaStore.Images.Media.TITLE, "New Picture")
            put(MediaStore.Images.Media.DESCRIPTION, "From Camera")
        }

        cameraImageUri = contentResolver.insert(
            MediaStore.Images.Media.EXTERNAL_CONTENT_URI,
            values
        )

        val cameraIntent = Intent(MediaStore.ACTION_IMAGE_CAPTURE).apply {
            putExtra(MediaStore.EXTRA_OUTPUT, cameraImageUri)
        }

        fileChooserLauncher.launch(cameraIntent)
    }

    private fun openFileChooser() {
        val intent = Intent(Intent.ACTION_GET_CONTENT).apply {
            type = "*/*"
            addCategory(Intent.CATEGORY_OPENABLE)
        }

        val chooserIntent = Intent.createChooser(intent, "Select File")
        fileChooserLauncher.launch(chooserIntent)
    }

    override fun onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack()
        } else {
            super.onBackPressed()
        }
    }

    inner class WebAppInterface(private val context: Context) {
        
        @JavascriptInterface
        fun capturePhoto(callback: String) {
            runOnUiThread {
                if (ContextCompat.checkSelfPermission(
                        context,
                        Manifest.permission.CAMERA
                    ) == PackageManager.PERMISSION_GRANTED
                ) {
                    launchCamera(callback)
                } else {
                    ActivityCompat.requestPermissions(
                        context as Activity,
                        arrayOf(Manifest.permission.CAMERA),
                        CAMERA_REQUEST_CODE
                    )
                    executeCallback(callback, createErrorResponse("Camera permission not granted"))
                }
            }
        }

        private fun launchCamera(callback: String) {
            val values = ContentValues().apply {
                put(MediaStore.Images.Media.TITLE, "Photo_${System.currentTimeMillis()}")
                put(MediaStore.Images.Media.MIME_TYPE, "image/jpeg")
            }

            val imageUri = context.contentResolver.insert(
                MediaStore.Images.Media.EXTERNAL_CONTENT_URI,
                values
            )

            val cameraIntent = Intent(MediaStore.ACTION_IMAGE_CAPTURE).apply {
                putExtra(MediaStore.EXTRA_OUTPUT, imageUri)
            }

            executeCallback(
                callback,
                createSuccessResponse(JSONObject().apply {
                    put("status", "launched")
                    put("uri", imageUri.toString())
                })
            )
        }

        @JavascriptInterface
        fun saveToLocalStorage(key: String, value: String, callback: String) {
            try {
                val sharedPreferences = context.getSharedPreferences(
                    "WebAppStorage",
                    Context.MODE_PRIVATE
                )
                sharedPreferences.edit().putString(key, value).apply()
                executeCallback(callback, createSuccessResponse(JSONObject().apply {
                    put("saved", true)
                    put("key", key)
                }))
            } catch (e: Exception) {
                executeCallback(callback, createErrorResponse(e.message ?: "Storage error"))
            }
        }

        @JavascriptInterface
        fun getFromLocalStorage(key: String, callback: String) {
            try {
                val sharedPreferences = context.getSharedPreferences(
                    "WebAppStorage",
                    Context.MODE_PRIVATE
                )
                val value = sharedPreferences.getString(key, null)
                executeCallback(callback, createSuccessResponse(JSONObject().apply {
                    put("key", key)
                    put("value", value ?: JSONObject.NULL)
                }))
            } catch (e: Exception) {
                executeCallback(callback, createErrorResponse(e.message ?: "Storage error"))
            }
        }

        @JavascriptInterface
        fun removeFromLocalStorage(key: String, callback: String) {
            try {
                val sharedPreferences = context.getSharedPreferences(
                    "WebAppStorage",
                    Context.MODE_PRIVATE
                )
                sharedPreferences.edit().remove(key).apply()
                executeCallback(callback, createSuccessResponse(JSONObject().apply {
                    put("removed", true)
                    put("key", key)
                }))
            } catch (e: Exception) {
                executeCallback(callback, createErrorResponse(e.message ?: "Storage error"))
            }
        }

        @JavascriptInterface
        fun clearLocalStorage(callback: String) {
            try {
                val sharedPreferences = context.getSharedPreferences(
                    "WebAppStorage",
                    Context.MODE_PRIVATE
                )
                sharedPreferences.edit().clear().apply()
                executeCallback(callback, createSuccessResponse(JSONObject().apply {
                    put("cleared", true)
                }))
            } catch (e: Exception) {
                executeCallback(callback, createErrorResponse(e.message ?: "Storage error"))
            }
        }

        @JavascriptInterface
        fun saveFile(filename: String, content: String, callback: String) {
            try {
                val file = File(context.filesDir, filename)
                FileOutputStream(file).use { output ->
                    output.write(content.toByteArray())
                }
                executeCallback(callback, createSuccessResponse(JSONObject().apply {
                    put("saved", true)
                    put("filename", filename)
                    put("path", file.absolutePath)
                }))
            } catch (e: Exception) {
                executeCallback(callback, createErrorResponse(e.message ?: "File save error"))
            }
        }

        @JavascriptInterface
        fun readFile(filename: String, callback: String) {
            try {
                val file = File(context.filesDir, filename)
                if (file.exists()) {
                    val content = FileInputStream(file).bufferedReader().use { it.readText() }
                    executeCallback(callback, createSuccessResponse(JSONObject().apply {
                        put("filename", filename)
                        put("content", content)
                    }))
                } else {
                    executeCallback(callback, createErrorResponse("File not found"))
                }
            } catch (e: Exception) {
                executeCallback(callback, createErrorResponse(e.message ?: "File read error"))
            }
        }

        @JavascriptInterface
        fun deleteFile(filename: String, callback: String) {
            try {
                val file = File(context.filesDir, filename)
                val deleted = file.delete()
                executeCallback(callback, createSuccessResponse(JSONObject().apply {
                    put("deleted", deleted)
                    put("filename", filename)
                }))
            } catch (e: Exception) {
                executeCallback(callback, createErrorResponse(e.message ?: "File delete error"))
            }
        }

        @JavascriptInterface
        fun listFiles(callback: String) {
            try {
                val files = context.filesDir.listFiles()
                val fileList = files?.map { it.name } ?: emptyList()
                executeCallback(callback, createSuccessResponse(JSONObject().apply {
                    put("files", JSONObject(fileList.joinToString(",")))
                }))
            } catch (e: Exception) {
                executeCallback(callback, createErrorResponse(e.message ?: "List files error"))
            }
        }

        @JavascriptInterface
        fun requestPushPermission(callback: String) {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
                if (ContextCompat.checkSelfPermission(
                        context,
                        Manifest.permission.POST_NOTIFICATIONS
                    ) != PackageManager.PERMISSION_GRANTED
                ) {
                    ActivityCompat.requestPermissions(
                        context as Activity,
                        arrayOf(Manifest.permission.POST_NOTIFICATIONS),
                        NOTIFICATION_REQUEST_CODE
                    )
                }
            }
            
            FirebaseMessaging.getInstance().token.addOnCompleteListener(OnCompleteListener { task ->
                if (!task.isSuccessful) {
                    executeCallback(callback, createErrorResponse("Failed to get FCM token"))
                    return@OnCompleteListener
                }

                val token = task.result
                executeCallback(callback, createSuccessResponse(JSONObject().apply {
                    put("token", token)
                    put("granted", true)
                }))
            })
        }

        @JavascriptInterface
        fun subscribeTopic(topic: String, callback: String) {
            FirebaseMessaging.getInstance().subscribeToTopic(topic)
                .addOnCompleteListener { task ->
                    if (task.isSuccessful) {
                        executeCallback(callback, createSuccessResponse(JSONObject().apply {
                            put("subscribed", true)
                            put("topic", topic)
                        }))
                    } else {
                        executeCallback(
                            callback,
                            createErrorResponse("Failed to subscribe to topic")
                        )
                    }
                }
        }

        @JavascriptInterface
        fun unsubscribeTopic(topic: String, callback: String) {
            FirebaseMessaging.getInstance().unsubscribeFromTopic(topic)
                .addOnCompleteListener { task ->
                    if (task.isSuccessful) {
                        executeCallback(callback, createSuccessResponse(JSONObject().apply {
                            put("unsubscribed", true)
                            put("topic", topic)
                        }))
                    } else {
                        executeCallback(
                            callback,
                            createErrorResponse("Failed to unsubscribe from topic")
                        )
                    }
                }
        }

        @JavascriptInterface
        fun showToast(message: String) {
            runOnUiThread {
                Toast.makeText(context, message, Toast.LENGTH_SHORT).show()
            }
        }

        @JavascriptInterface
        fun getDeviceInfo(callback: String) {
            val deviceInfo = JSONObject().apply {
                put("manufacturer", Build.MANUFACTURER)
                put("model", Build.MODEL)
                put("version", Build.VERSION.SDK_INT)
                put("versionRelease", Build.VERSION.RELEASE)
            }
            executeCallback(callback, createSuccessResponse(deviceInfo))
        }

        @JavascriptInterface
        fun vibrate(duration: Long) {
            runOnUiThread {
                val vibrator = context.getSystemService(Context.VIBRATOR_SERVICE) as android.os.Vibrator
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                    vibrator.vibrate(
                        android.os.VibrationEffect.createOneShot(
                            duration,
                            android.os.VibrationEffect.DEFAULT_AMPLITUDE
                        )
                    )
                } else {
                    @Suppress("DEPRECATION")
                    vibrator.vibrate(duration)
                }
            }
        }

        private fun createSuccessResponse(data: JSONObject): String {
            return JSONObject().apply {
                put("success", true)
                put("data", data)
            }.toString()
        }

        private fun createErrorResponse(message: String): String {
            return JSONObject().apply {
                put("success", false)
                put("error", message)
            }.toString()
        }

        private fun executeCallback(callback: String, response: String) {
            runOnUiThread {
                val escapedResponse = response.replace("'", "\\'")
                webView.evaluateJavascript("$callback('$escapedResponse')", null)
            }
        }
    }

    companion object {
